SELECT table_name FROM device_group WHERE `status` = 1 AND is_delete = 0 AND id IN (
#{item.id_device_group}
)

mapper.update:
UPDATE
	employee_chart_filter
SET
	name = #{name}
WHERE
	id = #{id}

mapper.delete:
  		WITH cte AS (
			SELECT
				id,
				ROW_NUMBER() OVER (ORDER BY id DESC) AS row_num
			FROM
				employee_chart_filter
			WHERE
				id_employee = #{id_employee}
				AND SHA1(id_site) = #{hash_id_site}
				AND is_favorite = #{is_favorite}
		)

  		DELETE FROM employee_chart_filter
	 	WHERE
	 		id_employee = #{id_employee}
	 		AND SHA1(id_site) = #{hash_id_site}
	 		AND is_favorite = #{is_favorite}
	 		AND id IN (SELECT id FROM cte WHERE row_num > 10)
